package example

import cats.effect.IO
import cats.effect.unsafe.IORuntime
import scala.concurrent.{ExecutionContext, Future}

final class Bridge(io: IO[Int])(using ExecutionContext, IORuntime):
  def asFuture(): Future[Int] = Future(io.unsafeRunSync())

package example

import cats.effect.IO
import scala.concurrent.{ExecutionContext, Future}

final class Bridge(future: => Future[Int])(using ExecutionContext):
  def asIO: IO[Int] = IO.fromFuture(IO(future))
